from flask import Flask, request, jsonify
import psycopg2
from psycopg2 import sql

app = Flask(__name__)

# Configure your PostgreSQL connection
DB_CONFIG = {
    'dbname': 'your_db_name',
    'user': 'your_db_user',
    'password': 'your_db_password',
    'host': 'your_db_host',
    'port': 'your_db_port'
}

def get_db_connection():
    conn = psycopg2.connect(**DB_CONFIG)
    return conn

@app.route('/query', methods=['POST'])
def query_database():
    data = request.get_json()
    table = data.get('table')
    columns = data.get('columns', '*')
    filters = data.get('filters', {})
    
    if not table:
        return jsonify({'error': 'Table name is required'}), 400

    try:
        with get_db_connection() as conn:
            with conn.cursor() as cur:
                query = sql.SQL("SELECT {fields} FROM {table} {where_clause}").format(
                    fields=sql.SQL(', ').join([sql.Identifier(col) for col in columns]),
                    table=sql.Identifier(table),
                    where_clause=sql.SQL("WHERE {conditions}").format(
                        conditions=sql.SQL(' AND ').join(
                            [sql.SQL("{} = %s").format(sql.Identifier(k)) for k in filters.keys()]
                        )
                    ) if filters else sql.SQL('')
                )

                cur.execute(query, list(filters.values()))
                result = cur.fetchall()
                column_names = [desc[0] for desc in cur.description]
                return jsonify([dict(zip(column_names, row)) for row in result])
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True)